"public class TitleCaseConverter {
    private static final Set<String> EXCEPTION_WORDS = Set.of(
        \"and\", \"of\", \"the\", \"is\", \"in\", \"on\", \"at\", \"by\", \"for\", \"with\", \"as\", \"an\", \"to\", \"from\", \"about\", \"over\", \"under\", \"up\", \"down\", \"out\", \"into\", \"through\", \"between\", \"among\", \"within\", \"upon\", \"before\", \"after\", \"since\", \"until\", \"during\", \"against\", \"toward\", \"throughout\", \"through\", \"across\", \"along\", \"around\", \"behind\", \"below\", \"beneath\", \"beside\", \"between\", \"beyond\", \"close\", \"concerning\", \"despite\", \"except\", \"following\", \"infront\", \"inside\", \"near\", \"next\", \"outside\", \"past\", \"regarding\", \"round\", \"since\", \"through\", \"throughout\", \"toward\", \"under\", \"underneath\", \"upon\", \"within\", \"without\"
    );

    public static String toTitleCase(String input) {
        if (input == null || input.isEmpty()) {
            return input;
        }

        String[] words = input.split(\"\\s+\");

        StringBuilder result = new StringBuilder();
        boolean firstWord = true;

        for (int i = 0; i < words.length; i++) {
            String word = words[i].trim();

            if (word.isEmpty()) {
                continue;
            }

            if (firstWord) {
                result.append(word.substring(0, 1).toUpperCase()).append(word.substring(1).toLowerCase());
                firstWord = false;
            } else {
                if (EXCEPTION_WORDS.contains(word.toLowerCase()) && i != 0) {
                    result.append(word.toLowerCase());
                } else {
                    result.append(word.substring(0, 1).toUpperCase()).append(word.substring(1).toLowerCase());
                }
            }

            if (i < words.length - 1) {
                result.append(\" \");
            }
        }

        return result.toString();
    }

